def test_create_onboarding_task_unauthenticated_returns_401(anon_session):
    payload = {
        "title": "Induction task",
        "description": "No auth test",
        "due_days": 2,
        "assignee_role": "employee"
    }
    resp = anon_session.post("/onboarding-tasks", json=payload)
    assert resp.status_code == 401, f"Expected 401 for unauthenticated request, got {resp.status_code}"

def test_create_onboarding_task_forbidden_role_returns_403(employee_session):
    payload = {
        "title": "Forbidden role task",
        "description": "Employee should not create tasks",
        "due_days": 2,
        "assignee_role": "employee"
    }
    resp = employee_session.post("/onboarding-tasks", json=payload)
    assert resp.status_code == 403, f"Expected 403 for forbidden role, got {resp.status_code}"
